GameListener = {}

local function hideEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    window:SetXPosition({ 100, 0 })
    window:SetVisible(false)
end

function GameListener:init()
    BaseListener.registerCallBack(GameReadyEvent, self.onGameReady)
    self:registerPacketHandler()
end

function GameListener.onGameReady()
    hideEngineWindow("MainControl-sneak")
    hideEngineWindow("Main-MoveState")
end

function GameListener:registerPacketHandler()
    CommonDataEvents:registerCallBack("UseArrowTip", function(data)
        local startPos = data:getVector3Param("startPos")
        local endPos = data:getVector3Param("endPos")
        local yaw = math.atan2(endPos.x - startPos.x, endPos.z - startPos.z) / math.pi * -180
        local distance = math.sqrt((startPos.x - endPos.x) * (startPos.x - endPos.x) + (startPos.z - endPos.z) * (startPos.z - endPos.z))
        distance = math.max(distance, 0.1)
        local arrowPos = VectorUtil.newVector3(0, startPos.y, 0)
        arrowPos.x = startPos.x + ((endPos.x - startPos.x) / distance) * math.min(distance - 1, 5)
        arrowPos.z = startPos.z + ((endPos.z - startPos.z) / distance) * math.min(distance - 1, 5)
        local entityId = EngineWorld:addActorNpc(arrowPos, yaw, "arrow02.actor")
        LuaTimer:schedule(function()
            EngineWorld:removeEntity(entityId)
        end, 5000)
    end, DataBuilderProcessor)
end

return GameListener